var SUPABASE_URL = $env.SUPABASE_URL;
var SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
if (!SUPABASE_URL || !SUPABASE_KEY) throw new Error('Faltan variables SUPABASE_URL o SUPABASE_SERVICE_KEY');
var staticData = $getWorkflowStaticData('global');
staticData.offset = 0;
staticData.totalEnriquecidos = 0;
staticData.totalFallidos = 0;
var LIMIT = 500;
var resp = await this.helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/ferreterias?select=id,razon_social,telefono,email,num_fuentes&or=(telefono.is.null,email.is.null)&order=id.asc&limit=' + LIMIT + '&offset=' + staticData.offset,
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
});
if (!Array.isArray(resp) || resp.length === 0) {
  return [{ json: { _fin: true } }];
}
staticData.offset += resp.length;
var tieneMas = resp.length === LIMIT;
return resp.map(function(r) { return { json: Object.assign({}, r, { _tiene_mas: tieneMas }) }; });

var SUPABASE_URL = $env.SUPABASE_URL;
var SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
var GROQ_KEY = $env.GROQ_API_KEY;
var staticData = $getWorkflowStaticData('global');
var items = $input.all();
var tieneMas = items.some(function(i){ return i.json._tiene_mas === true; });

function toSlug(n) {
  var stop = {'Y':1,'DE':1,'DEL':1,'LA':1,'LAS':1,'LOS':1,'EL':1,'EN':1,'A':1,'E':1,'CON':1,'POR':1,'PARA':1,'SU':1,'AL':1,'UN':1,'UNA':1};
  return n.toUpperCase()
    .replace(/[\u00c1\u00c0]/g,'A').replace(/[\u00c9\u00c8]/g,'E')
    .replace(/[\u00cd\u00cc]/g,'I').replace(/[\u00d3\u00d2]/g,'O')
    .replace(/[\u00da\u00d9]/g,'U').replace(/\u00d1/g,'N')
    .replace(/\./g,'').replace(/,/g,'').replace(/&/g,'')
    .replace(/[^A-Z0-9\s]/g,'')
    .split(/\s+/).filter(function(w){ return w && !stop[w]; })
    .join('-').replace(/-+/g,'-');
}

for (var i = 0; i < items.length; i++) {
  var item = items[i].json;
  var slug = toSlug(item.razon_social);
  var url = 'https://empresas.portafolio.co/' + slug + '.html';
  var tel = null, email = null, html_fragment = '';

  try {
    var html = await Promise.race([
      this.helpers.httpRequest({
        method: 'GET', url: url,
        headers: {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
          'Accept-Language': 'es-CO,es;q=0.9'
        }
      }),
      new Promise(function(resolve){ setTimeout(function(){ resolve(''); }, 3000); })
    ]);
    if (html && !html.includes('Demasiadas peticiones') && !html.includes('reCAPTCHA')) {
      var mTel = html.match(/<span[^>]+itemprop=["']telephone["'][^>]*>([^<]+)<\/span>/i);
      var mEmail = html.match(/<span[^>]+itemprop=["']email["'][^>]*>([^<]+)<\/span>/i);
      if (mTel) tel = mTel[1].trim();
      if (mEmail) email = mEmail[1].trim();
      if (!tel && !email) {
        var idx = html.indexOf('listData');
        var raw = idx !== -1 ? html.substring(Math.max(0,idx-100), idx+2000) : html.substring(0,2500);
        html_fragment = raw.replace(/<script[^>]*>[\s\S]*?<\/script>/gi,'').substring(0,2000);
      }
    }
  } catch(e) { console.log('Fetch error ' + item.razon_social + ': ' + e.message); }

  if (!tel && !email && html_fragment) {
    try {
      var groqResp = await this.helpers.httpRequest({
        method: 'POST',
        url: 'https://api.groq.com/openai/v1/chat/completions',
        headers: { 'Authorization': 'Bearer ' + GROQ_KEY, 'Content-Type': 'application/json' },
        body: JSON.stringify({
          model: 'llama-3.1-8b-instant',
          messages: [
            { role: 'system', content: 'Eres un extractor de datos. Responde SOLO con JSON valido: {"telefono": "NUMERO", "email": "CORREO"}. Usa null si no encuentras. Sin texto adicional.' },
            { role: 'user', content: 'Empresa: ' + item.razon_social + '\n\nHTML:\n' + html_fragment }
          ],
          temperature: 0, max_tokens: 80
        })
      });
      var content = groqResp.choices[0].message.content.trim();
      var jsonMatch = content.match(/\{[\s\S]*?\}/);
      if (jsonMatch) {
        var datos = JSON.parse(jsonMatch[0]);
        tel = datos.telefono || null;
        email = datos.email || null;
      }
      console.log('Groq ' + item.razon_social + ': tel=' + tel + ', email=' + email);
    } catch(e) { console.log('Groq error: ' + e.message); }
  }

  if (tel || email) {
    var patch = { num_fuentes: (item.num_fuentes || 1) + 1 };
    if (!item.telefono && tel) patch.telefono = tel;
    if (!item.email && email) patch.email = email;
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: SUPABASE_URL + '/rest/v1/ferreterias?id=eq.' + item.id,
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
        body: JSON.stringify(patch)
      });
      staticData.totalEnriquecidos = (staticData.totalEnriquecidos || 0) + 1;
      console.log('OK: ' + item.razon_social + ' tel=' + tel);
    } catch(e) { console.error('PATCH error: ' + e.message); }
  } else {
    staticData.totalFallidos = (staticData.totalFallidos || 0) + 1;
    console.log('Sin datos: ' + item.razon_social);
  }

  await new Promise(function(r){ setTimeout(r, 1000); });
}

return [{ json: { _tiene_mas: tieneMas, total_enriquecidos: staticData.totalEnriquecidos, total_fallidos: staticData.totalFallidos } }];
